function getItem(name, index) {
  try {
    const items = $items(name);
    return items[index]?.json || items[0]?.json || {};
  } catch (e) {
    return {};
  }
}
function asArray(value) {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    try { const parsed = JSON.parse(value); return Array.isArray(parsed) ? parsed : []; } catch (e) { return []; }
  }
  return [];
}
function classify(testCase, finalTx, evidence) {
  const expected = String(testCase.expected_action || '').toLowerCase();
  const actualStatus = finalTx.status || 'unknown';
  const retrievalStatus = finalTx.retrieval_status || 'unknown';
  const refusalReason = finalTx.refusal_reason || '';
  const selectedCount = Number(evidence.selected_context_count || 0);
  const hasContext = retrievalStatus === 'context_found' || selectedCount >= Number(testCase.min_result_count || 3);
  if (actualStatus === 'failed' || finalTx.failure_reason) {
    return { outcome: 'workflow_failure', failure_type: finalTx.failure_reason || 'workflow_failed', review_notes: 'Workflow failed before a usable retrieval result.' };
  }
  if (expected === 'refuse') {
    if (actualStatus === 'refused' || retrievalStatus === 'no_context') {
      return { outcome: 'pass', failure_type: '', review_notes: 'Expected refusal/no-context behavior observed.' };
    }
    if (hasContext) {
      return { outcome: 'review_needed', failure_type: 'possible_missed_refusal', review_notes: 'Retrieval found context for a refusal-labeled case; label or retrieval should be reviewed.' };
    }
    return { outcome: 'missed_refusal', failure_type: 'refusal_expected_but_not_observed', review_notes: 'Expected refusal but result did not clearly refuse.' };
  }
  if (actualStatus === 'refused' || retrievalStatus === 'no_context' || !hasContext) {
    return { outcome: 'false_refusal', failure_type: refusalReason || 'expected_answer_but_no_context', review_notes: 'Expected answer but retrieval/core produced no usable context.' };
  }
  return { outcome: 'pass', failure_type: '', review_notes: 'Expected answer and retrieval/context evidence was produced.' };
}

return $input.all().map((item, index) => {
  const evidence = item.json || {};
  const testCase = getItem('Load Regression Cases', index);
  const finalTx = getItem('Call Intake Workflow', index);
  const selectedChunks = asArray(evidence.selected_chunks);
  const candidateReport = asArray(evidence.candidate_report);
  const result = classify(testCase, finalTx, evidence);
  const answerText = finalTx.answer_text || finalTx.discord_response_text || finalTx.gemini_response_text || null;
  const transactionTrace = {
    transaction_id: finalTx.transaction_id || null,
    trace_id: finalTx.query_hash || null,
    status: finalTx.status || null,
    retrieval_status: finalTx.retrieval_status || null,
    response_status: finalTx.response_status || null,
    refusal_reason: finalTx.refusal_reason || null,
    failure_reason: finalTx.failure_reason || null,
    latency_ms: finalTx.latency_ms ?? null
  };
  const report = {
    case_id: testCase.case_id,
    category: testCase.category,
    question: testCase.question,
    expected_action: testCase.expected_action,
    expected_behavior: testCase.expected_behavior,
    outcome: result.outcome,
    failure_type: result.failure_type,
    review_notes: result.review_notes,
    transaction_trace: transactionTrace,
    selected_context_count: Number(evidence.selected_context_count || 0),
    context_token_estimate: evidence.context_token_estimate ?? null,
    selected_chunks: selectedChunks,
    candidate_report: candidateReport,
    answer_provided: answerText,
    answer_note: answerText ? 'Answer captured from full-answer mode.' : 'No answer text captured; retrieval_only mode skips Gemini and Discord.'
  };
  const payload = {
    case_id: testCase.case_id,
    category: testCase.category,
    expected_action: testCase.expected_action,
    expected_behavior: testCase.expected_behavior,
    actual_status: finalTx.status || null,
    retrieval_status: finalTx.retrieval_status || null,
    response_status: finalTx.response_status || null,
    refusal_reason: finalTx.refusal_reason || null,
    failure_reason: finalTx.failure_reason || null,
    selected_context_count: Number(evidence.selected_context_count || 0),
    selected_channels: evidence.selected_channels || [],
    selected_chunk_ids: evidence.selected_chunk_ids || [],
    retrieval_scores: evidence.retrieval_scores || [],
    reranker_scores: evidence.reranker_scores || [],
    context_token_estimate: evidence.context_token_estimate ?? null,
    latency_ms: finalTx.latency_ms ?? null,
    outcome: result.outcome,
    failure_type: result.failure_type,
    review_notes: result.review_notes,
    selected_chunks: selectedChunks,
    candidate_report: candidateReport,
    answer_provided: answerText,
    transaction_trace: transactionTrace
  };
  const sqlPayload = JSON.stringify(payload).replace(/'/g, "''");
  return {
    json: {
      ...testCase,
      ...payload,
      transaction_id: finalTx.transaction_id || null,
      trace_id: finalTx.query_hash || null,
      answer_length: answerText ? String(answerText).length : null,
      citation_status: finalTx.citation_status || null,
      regression_report: report,
      result_payload_sql_json: sqlPayload
    }
  };
});

const rows = $items('Classify Regression Results').map(item => item.json || {});
const total = rows.length;
const counts = rows.reduce((acc, row) => {
  acc[row.outcome] = (acc[row.outcome] || 0) + 1;
  return acc;
}, {});
const passCount = counts.pass || 0;
const reviewCount = counts.review_needed || 0;
const failCount = total - passCount - reviewCount;
const runId = rows[0]?.run_id || $items('Load Regression Cases')[0]?.json?.regression_run_id;
return [{
  json: {
    run_id: runId,
    status: 'completed',
    total_cases: total,
    pass_count: passCount,
    fail_count: failCount,
    review_count: reviewCount,
    outcome_counts: counts,
    report_schema: 'phase8.regression_report.v2',
    report_note: 'retrieval_only mode intentionally skips Gemini and Discord, so answer_provided is normally null.',
    cases: rows.map(row => row.regression_report || {
      case_id: row.case_id,
      category: row.category,
      question: row.question,
      expected_action: row.expected_action,
      outcome: row.outcome,
      failure_type: row.failure_type,
      transaction_trace: {
        transaction_id: row.transaction_id,
        trace_id: row.trace_id,
        actual_status: row.actual_status,
        retrieval_status: row.retrieval_status,
        refusal_reason: row.refusal_reason,
        failure_reason: row.failure_reason,
        latency_ms: row.latency_ms
      },
      selected_context_count: row.selected_context_count,
      selected_chunks: row.selected_chunks || [],
      candidate_report: row.candidate_report || [],
      answer_provided: row.answer_provided || null
    }),
    completed_at: new Date().toISOString()
  }
}];
